#!/usr/bin/env python3\n\"\"\"\nHeadless Drone Simulator - Physics Verification\n\nRuns the drone physics loop without GUI, printing telemetry to console.\nUseful for verifying physics behavior and debugging.\n\nUsage:\n    python test_headless_sim.py\n\"\"\"\n\nimport numpy as np\nimport sys\nfrom pathlib import Path\n\nsys.path.insert(0, str(Path(__file__).parent))\n\nfrom physics.drone import Drone\nfrom physics.battery import Battery\nfrom physics.environment import Environment\nfrom control.mixer import Mixer\nfrom control.pid import PIDController\n\n\nclass HeadlessSimulator:\n    \"\"\"\n    Runs drone simulation headless (no GUI).\n    \"\"\"\n    \n    def __init__(\n        self,\n        sim_time: float = 30.0,\n        physics_dt: float = 0.001,\n        print_interval: float = 0.5\n    ):\n        \"\"\"\n        Initialize headless simulator.\n        \n        Args:\n            sim_time: total simulation time (seconds)\n            physics_dt: physics timestep (seconds)\n            print_interval: telemetry print interval (seconds)\n        \"\"\"\n        self.sim_time = sim_time\n        self.physics_dt = physics_dt\n        self.print_interval = print_interval\n        self.time = 0.0\n        self.last_print = -print_interval\n        \n        # Create drone\n        self.drone = self._create_drone()\n        \n        # Create mixer\n        self.mixer = Mixer(drone_type=\"quad_x\", num_rotors=4)\n        \n        # Create PID controllers for attitude stabilization\n        self.roll_pid = PIDController(kp=4.5, ki=0.05, kd=0.2, dt=physics_dt)\n        self.pitch_pid = PIDController(kp=4.5, ki=0.05, kd=0.2, dt=physics_dt)\n        self.yaw_pid = PIDController(kp=0.15, ki=0.05, kd=0.004, dt=physics_dt)\n        \n        # Desired setpoints\n        self.desired_throttle = 0.0  # 0-1\n        self.desired_roll = 0.0  # radians\n        self.desired_pitch = 0.0\n        self.desired_yaw_rate = 0.0\n    \n    def _create_drone(self) -> Drone:\n        \"\"\"\n        Create a standard quadcopter drone.\n        \"\"\"\n        # Drone mass (excluding battery)\n        mass = 1.0  # kg\n        \n        # Principal moments of inertia\n        inertia = np.array([0.018, 0.018, 0.032])  # kg*m²\n        \n        # Rotor configuration (quad-X)\n        rotor_configs = [\n            {\n                \"position\": np.array([0.215, 0.215, 0.0]),\n                \"direction\": 1,\n                \"kv\": 920,\n                \"k_thrust\": 9.65e-5,\n                \"k_drag\": 1.2e-6,\n                \"i_rotor\": 1e-5,\n                \"r_internal\": 0.01\n            },\n            {\n                \"position\": np.array([-0.215, 0.215, 0.0]),\n                \"direction\": -1,\n                \"kv\": 920,\n                \"k_thrust\": 9.65e-5,\n                \"k_drag\": 1.2e-6,\n                \"i_rotor\": 1e-5,\n                \"r_internal\": 0.01\n            },\n            {\n                \"position\": np.array([-0.215, -0.215, 0.0]),\n                \"direction\": 1,\n                \"kv\": 920,\n                \"k_thrust\": 9.65e-5,\n                \"k_drag\": 1.2e-6,\n                \"i_rotor\": 1e-5,\n                \"r_internal\": 0.01\n            },\n            {\n                \"position\": np.array([0.215, -0.215, 0.0]),\n                \"direction\": -1,\n                \"kv\": 920,\n                \"k_thrust\": 9.65e-5,\n                \"k_drag\": 1.2e-6,\n                \"i_rotor\": 1e-5,\n                \"r_internal\": 0.01\n            }\n        ]\n        \n        # Battery: 3S LiPo 5000mAh\n        battery = Battery(\n            capacity_mah=5000,\n            nominal_voltage=11.1,\n            internal_resistance=0.012,\n            c_rating=50,\n            num_cells=3\n        )\n        \n        # Environment\n        environment = Environment(\n            gravity=9.81,\n            rho_sea_level=1.225,\n            wind_speed=0.0,\n            wind_direction=0.0\n        )\n        \n        # Create drone\n        drone = Drone(\n            mass=mass,\n            inertia=inertia,\n            rotor_configs=rotor_configs,\n            battery=battery,\n            environment=environment,\n            dt=self.physics_dt\n        )\n        \n        return drone\n    \n    def get_euler_angles(self) -> np.ndarray:\n        \"\"\"\n        Extract Euler angles (roll, pitch, yaw) from quaternion.\n        \n        Returns:\n            [roll, pitch, yaw] in radians\n        \"\"\"\n        q = self.drone.body.get_quaternion()\n        qw, qx, qy, qz = q\n        \n        # Roll (phi)\n        roll = np.arctan2(2*(qw*qx + qy*qz), 1 - 2*(qx**2 + qy**2))\n        \n        # Pitch (theta)\n        sin_pitch = 2*(qw*qy - qz*qx)\n        sin_pitch = np.clip(sin_pitch, -1, 1)\n        pitch = np.arcsin(sin_pitch)\n        \n        # Yaw (psi)\n        yaw = np.arctan2(2*(qw*qz + qx*qy), 1 - 2*(qy**2 + qz**2))\n        \n        return np.array([roll, pitch, yaw])\n    \n    def attitude_controller(self):\n        \"\"\"\n        Simple attitude controller.\n        Converts desired roll/pitch/yaw to motor throttles.\n        \"\"\"\n        # Get current attitude\n        roll, pitch, yaw = self.get_euler_angles()\n        omega = self.drone.body.get_angular_velocity()\n        \n        # PID errors\n        roll_error = self.desired_roll - roll\n        pitch_error = self.desired_pitch - pitch\n        yaw_rate_error = self.desired_yaw_rate - omega[2]\n        \n        # PID outputs\n        roll_moment = self.roll_pid.update(roll_error)\n        pitch_moment = self.pitch_pid.update(pitch_error)\n        yaw_moment = self.yaw_pid.update(yaw_rate_error)\n        \n        # Mix to motor throttles\n        throttles = self.mixer.mix(\n            thrust=self.desired_throttle,\n            roll_moment=roll_moment,\n            pitch_moment=pitch_moment,\n            yaw_moment=yaw_moment\n        )\n        \n        # Set motor throttles\n        self.drone.set_motor_throttles(throttles)\n    \n    def print_telemetry(self):\n        \"\"\"\n        Print simulation telemetry to console.\n        \"\"\"\n        if self.time - self.last_print < self.print_interval:\n            return\n        \n        self.last_print = self.time\n        \n        # State\n        pos = self.drone.body.get_position()\n        vel = self.drone.body.get_velocity()\n        roll, pitch, yaw = self.get_euler_angles()\n        omega = self.drone.body.get_angular_velocity()\n        \n        # Battery\n        soc = self.drone.battery.get_soc()\n        v_terminal = self.drone.battery.get_terminal_voltage(self.drone.total_current)\n        \n        # Motors\n        rpms = [rotor.get_rpm() for rotor in self.drone.rotors]\n        thrusts = [rotor.get_thrust(self.drone.environment.get_air_density(pos[2])) \n                   for rotor in self.drone.rotors]\n        \n        print(f\"\\n{'='*80}\")\n        print(f\"Time: {self.time:7.2f}s | Throttle: {self.desired_throttle:.2f}\")\n        print(f\"{'='*80}\")\n        \n        # Position and velocity\n        print(f\"Position [m]:     X={pos[0]:7.3f}  Y={pos[1]:7.3f}  Z={pos[2]:7.3f}\")\n        print(f\"Velocity [m/s]:   X={vel[0]:7.3f}  Y={vel[1]:7.3f}  Z={vel[2]:7.3f} (speed={np.linalg.norm(vel):.3f})\")\n        \n        # Attitude\n        print(f\"Attitude [deg]:   Roll={np.rad2deg(roll):7.2f}  Pitch={np.rad2deg(pitch):7.2f}  Yaw={np.rad2deg(yaw):7.2f}\")\n        print(f\"Ang Vel [rad/s]:  P={omega[0]:7.3f}  Q={omega[1]:7.3f}  R={omega[2]:7.3f}\")\n        \n        # Battery\n        print(f\"Battery:          V={v_terminal:6.2f}V  I={self.drone.total_current:6.2f}A  SOC={soc*100:5.1f}%  T={self.drone.battery.temperature:5.1f}°C\")\n        \n        # Motors\n        print(f\"Motors [RPM]:     M0={rpms[0]:6.0f}  M1={rpms[1]:6.0f}  M2={rpms[2]:6.0f}  M3={rpms[3]:6.0f}\")\n        print(f\"Thrusts [N]:      T0={thrusts[0]:6.2f}  T1={thrusts[1]:6.2f}  T2={thrusts[2]:6.2f}  T3={thrusts[3]:6.2f}  Total={sum(thrusts):6.2f}\")\n        print(f\"Throttles:        T0={self.drone.rotors[0].throttle:5.3f}  T1={self.drone.rotors[1].throttle:5.3f}  T2={self.drone.rotors[2].throttle:5.3f}  T3={self.drone.rotors[3].throttle:5.3f}\")\n    \n    def set_hover_throttle(self):\n        \"\"\"\n        Calculate and set throttle needed to hover (gravity balance).\n        \"\"\"\n        # Total mass including battery\n        total_mass = self.drone.body.mass\n        \n        # Hover force = weight\n        hover_force = total_mass * 9.81\n        \n        # Estimate thrust per rotor (equally distributed for hover)\n        thrust_per_rotor = hover_force / 4\n        \n        # Rough approximation: throttle ≈ thrust / max_thrust\n        # For now, use a heuristic: max_thrust at 1.0 throttle ≈ 15 N per rotor\n        # This is tuned for the default drone params\n        max_thrust_per_rotor = 15.0\n        throttle = thrust_per_rotor / max_thrust_per_rotor\n        throttle = np.clip(throttle, 0.0, 1.0)\n        \n        self.desired_throttle = throttle\n    \n    def run(self):\n        \"\"\"\n        Run the simulation loop.\n        \"\"\"\n        print(\"\\n\" + \"=\"*80)\n        print(\"EV DRONE FLIGHT SIMULATOR - HEADLESS TEST\")\n        print(\"=\"*80)\n        print(f\"Physics timestep: {self.physics_dt*1000:.1f} ms\")\n        print(f\"Simulation time: {self.sim_time}s\")\n        print(f\"Drone mass: {self.drone.body.mass:.2f} kg\")\n        print(f\"Battery: {self.drone.battery.capacity_mah} mAh @ {self.drone.battery.nominal_voltage}V\")\n        print(\"=\"*80)\n        \n        # Test phases\n        phase_time = self.sim_time / 4\n        \n        while self.time < self.sim_time:\n            # Determine phase and set desired state\n            phase = int(self.time / phase_time)\n            \n            if phase == 0:\n                # Phase 0 (0-7.5s): Resting on ground\n                self.desired_throttle = 0.0\n            \n            elif phase == 1:\n                # Phase 1 (7.5-15s): Calculate and apply hover throttle\n                self.set_hover_throttle()\n            \n            elif phase == 2:\n                # Phase 2 (15-22.5s): Climb (increase throttle)\n                self.set_hover_throttle()\n                self.desired_throttle += 0.01 * (self.time - phase_time*2) / phase_time\n                self.desired_throttle = min(self.desired_throttle, 0.75)\n            \n            elif phase == 3:\n                # Phase 3 (22.5-30s): Descend\n                self.desired_throttle *= 0.98\n                self.desired_throttle = max(self.desired_throttle, 0.0)\n            \n            # Apply attitude controller\n            self.attitude_controller()\n            \n            # Physics step\n            self.drone.step()\n            \n            # Print telemetry\n            self.print_telemetry()\n            \n            # Advance time\n            self.time += self.physics_dt\n        \n        print(f\"\\n{'='*80}\")\n        print(\"SIMULATION COMPLETE\")\n        print(f\"Final battery SOC: {self.drone.battery.get_soc()*100:.1f}%\")\n        print(f\"Final position: {self.drone.body.get_position()}\")\n        print(f\"{'='*80}\\n\")\n\n\nif __name__ == \"__main__\":\n    # Run simulation\n    sim = HeadlessSimulator(sim_time=30.0, physics_dt=0.001, print_interval=0.5)\n    sim.run()\n"